export default function BarraProgreso({ progreso }) {
  return (
    <div style={{ width: "100%", background: "#eee", borderRadius: "4px", marginBottom: "1rem" }}>
      <div
        style={{
          width: `${progreso}%`,
          background: "#4caf50",
          height: "20px",
          borderRadius: "4px",
          transition: "width 0.3s",
        }}
      />
    </div>
  );
}
